async function getPreference(key: string): Promise<string | null> {
  // Try local first (instant)
  const local = localStorage.getItem(key);
  if (local) return local;
  // Fallback to server
  try {
    const r = await fetch(`/api/preferences/${key}`);
    const value = await r.json();
    if (value) localStorage.setItem(key, value);
    return value;
  } catch {
    return null;
  }
}

async function setPreference(key: string, value: string) {
  localStorage.setItem(key, value);
  // Background sync
  fetch(`/api/preferences/${key}`, { method: 'PUT', body: JSON.stringify({ value }) }).catch(() => {});
}

import { Slot } from '@radix-ui/react-slot';

interface BoxProps extends React.HTMLAttributes<HTMLDivElement> {
  asChild?: boolean;
}

export function Box({ asChild, className, ...props }: BoxProps) {
  const Comp = asChild ? Slot : 'div';
  return <Comp className={`box ${className ?? ''}`} {...props} />;
