function useProducts(filters: { category?: string; sort?: string; page?: number }) {
  return useQuery({
    queryKey: ['products', filters],  // Different filter = different cache entry
    queryFn: () => fetch(`/api/products?${new URLSearchParams(filters as any)}`).then(r => r.json()),
    staleTime: 30_000
  });
}

