} as const;

type Variant = keyof typeof variants;
type VariantStyles = (typeof variants)[Variant];

function Button({ variant }: { variant: Variant }) {
  const styles = variants[variant];
  return <button className={`${styles.bg} ${styles.text}`} />;
}

